module dram_cell (  
    input [15:0] data_in,  
    input RE,  
    input WE,  
    input CLK,  
    output reg [15:0] data_out  
);  
    reg [15:0] cell_data;  

    always @(posedge CLK) begin  
        if (WE)  
            cell_data <= data_in;  
        if (RE)  
            data_out <= cell_data;  
    end  
endmodule
